#!/usr/bin/env python

import os
import subprocess

def main():
    # Install requirements from requirements.txt without hash verification for speed
    subprocess.run(["pip", "install", "-r", "requirements.txt", "--no-hash"])

    # Upgrade packages to latest versions with --upgrade flag
    subprocess.run(["pip", "list", "--outdated"], stdout=subprocess.PIPE)
    outdated_packages = [line.split()[0] for line in subprocess.stdout]
    if len(outdated_packages):
        subprocess.run(["pip", "install", "--upgrade"] + outdated_packages)

if __name__ == "__main__":
    main()